@Slf4j
public abstract class AbstractBijdragePercentages implements BijdragePercentages {
    public static final int SCHUIF_FACTOR_100 = 2;
    public static final int PERCENTAGE_BIJDRAGE_PRECISIE = 5;
    public static final int PROVANT_0_PRCT = 89;
    private static final Set<RekenPatronaalRszKey> PATRONALE_VOERTUIG_KEYS =
