                    RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_3_KEY);

    protected final RegulManager regulManager;
    protected final RekenRszConstantService rekenRszConstantService;
    private final ConstantManager constantManager;
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;
    private final DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService;
    private final RekenTijd rekenTijd;
    private final IsPool2Ter isPool2ter;
    private final AsbestfondsManager asbestfondsManager;

    private final BijdragePensioenDmfappl bijdragePensioen;
    private final PatronaleBijdragePensioenDmfappl patronaleBijdragePensioen;
    private final PatronaleBijdrageCoronaPremie patronaleBijdrageCoronaPremie;
    private final BijdrageWvl bijdrageWvl;
    private final PatronaleBijdrageWvl patronaleBijdrageWvl;


    public AbstractBijdragePercentages(
            ConstantManager constantManager, RegulManager regulManager, RszConstantService rszConstantService,
            DmfapplBasisBijdrageService dmfapplBasisBijdrageService,
            DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService, IsPool2Ter isPool2Ter, AsbestfondsManager asbestfondsManager,
            RekenTijd rekenTijd) {
        this.dmfapplBasisBijdrageService = dmfapplBasisBijdrageService;
        this.dmfaVerminderingsPercentageService = dmfaVerminderingsPercentageService;
        this.constantManager = constantManager;
        this.regulManager = regulManager;
        this.rekenTijd = rekenTijd;
        this.isPool2ter = isPool2Ter;
        this.asbestfondsManager = asbestfondsManager;
        this.rekenRszConstantService = new RekenRszConstantService(rszConstantService, regulManager);
        this.bijdragePensioen = new BijdragePensioenDmfappl(rekenRszConstantService);
        this.patronaleBijdragePensioen = new PatronaleBijdragePensioenDmfappl(rekenRszConstantService);
        this.patronaleBijdrageCoronaPremie = new PatronaleBijdrageCoronaPremie(rszConstantService);
        this.bijdrageWvl = new BijdrageWvl(this);
        this.patronaleBijdrageWvl = new PatronaleBijdrageWvl(this);
    }

    private static boolean isVakantieregelingPrive(SleutelGegevens gegevens) {
        WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
        return werkgeversCategorie == WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_OPENBAAR_DMFA
                || werkgeversCategorie == WerkgeversCategorie.CONTRACTUELEN_VAKANTIEREGELING_PRIVE_ARBREG_PRIVE_DMFA;
    }

    @Override
    public BigDecimal getInhoudingRsz(SleutelGegevens gegevens) {
        LocalDate zoekDatum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        return getInhoudingRsz(gegevens, zoekDatum);
    }

    @Override
    public BigDecimal getInhoudingRsz(SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal inhoudingPercentage = BigDecimal.ZERO;
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        LocalDate datum = RszTools.zoekDatumAanpassenVoorVervallenWnkKengetallen(werknemersKengetal, zoekDatum);
        RszConstant rszConstant = rekenRszConstantService.getRszConstantChecked(gegevens, datum, werknemersKengetal, gegevens.getWerkgeversCategorie());

        if (rszConstant != null) {
            inhoudingPercentage = rszConstant.getWerknemersPercentage();
        }
        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    @Override
    public BigDecimal getPatronaleBijdrageRsz(SleutelGegevens gegevens) {
        LocalDate datum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        return getPatronaleBijdrageRsz(gegevens, datum);
    }

    @Override
    public BigDecimal getPatronaleBijdrageRsz(SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal bijdragePercentage = BigDecimal.ZERO;
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        LocalDate datum = RszTools.zoekDatumAanpassenVoorVervallenWnkKengetallen(werknemersKengetal, zoekDatum);

        RszConstant rszConstant = rekenRszConstantService.getRszConstantChecked(gegevens, datum, werknemersKengetal, gegevens.getWerkgeversCategorie());
        if (rszConstant != null) {
            bijdragePercentage = rszConstant.getWerkgeversPercentage();
        }
        bijdragePercentage = bijdragePercentage.add(asbestfondsManager.getPercentageLosVanBasis(werknemersKengetal, zoekDatum));
        return bijdragePercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    @Override
    public BigDecimal getVerminderingPatronaleBijdrageRsz(SleutelGegevens gegevens) {
        LocalDate datum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        return getVerminderingPatronaleBijdrageRsz(gegevens, datum);
    }

    @Override
    public BigDecimal getVerminderingPatronaleBijdrageRsz(SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal bijdragePercentage = BigDecimal.ZERO;
        DmfaVerminderingsPercentage verminderingsPercentage = dmfaVerminderingsPercentageService.getByWerkgeversCategorieWerknemersKengetalVerminderingsCodeDatum(
                gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(), gegevens.getVerminderingsCode(), zoekDatum);
        if (verminderingsPercentage != null) {
            bijdragePercentage = verminderingsPercentage.getVerminderingsPercentage();
        }
        return bijdragePercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

