    @Override
    public BigDecimal getPatronaleBijdrageTweedePensioenPijler(SleutelGegevens gegevens) {
        LocalDate datum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        return getPatronaleBijdrageTweedePensioenPijler(gegevens, datum);
    }

    @Override
    public BigDecimal getPatronaleBijdrageTweedePensioenPijler(SleutelGegevens gegevens, LocalDate zoekDatum) {
        BijdrageTweedePensioenPijler bijdrageTweedePensioenPijler = BijdrageTweedePensioenPijlerFactory.create(constantManager, zoekDatum, rekenTijd);
        int typeBijdrage = bijdrageTweedePensioenPijler.getTypeBijdrageAdjusted();
        if (typeBijdrage == PROVANT_0_PRCT) {
            return BigDecimal.ZERO;
        } else {
            DmfapplWnkengetal werknemersKengetalBijdrage = bijdrageTweedePensioenPijler.getBasisKengetal();

            RszConstant constante = rekenRszConstantService.getRszConstantChecked(gegevens, zoekDatum, werknemersKengetalBijdrage, typeBijdrage);
            BigDecimal inhoudingPercentage = (constante != null) ? constante.getWerkgeversPercentage() : BigDecimal.ZERO;
            return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
        }
    }

    @Override
    public BigDecimal getPatronaleBijdrageTweedePensioenPijlerAntwerpen(SleutelGegevens gegevens, LocalDate zoekDatum, boolean onderGrens, boolean jongerDan35) {
        int typeBijdrage = onderGrens ? 0 : 1;
        typeBijdrage = jongerDan35 ? typeBijdrage : (typeBijdrage + 2);
        KengetalMapper werknemersKengetalMapper = getWerknemersKengetalMapper(zoekDatum);
        DmfapplWnkengetal werknemersKengetalBijdrage = werknemersKengetalMapper.getCode843();
        RszConstant constante = rekenRszConstantService.getRszConstantChecked(gegevens, zoekDatum, werknemersKengetalBijdrage, typeBijdrage);
        BigDecimal inhoudingPercentage = (constante != null) ? constante.getWerkgeversPercentage() : BigDecimal.ZERO;
        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

