    @Override
    public BigDecimal getPatronaleBijdrageMeerDan10Werknemers(SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal inhoudingPercentage;
        if (heeftWerkloosheidsBijdrage169(gegevens, zoekDatum)) {
            inhoudingPercentage = getWerkloosheidsBijdrage169(gegevens, zoekDatum);
        } else {
            inhoudingPercentage = bepaalWerkloosheidsBijdrage160(gegevens, zoekDatum);
        }

        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    BigDecimal bepaalWerkloosheidsBijdrage160(SleutelGegevens gegevens, LocalDate zoekDatum) {
        if (heeftWerkloosheidsBijdrage160(gegevens, zoekDatum)) {
            return getWerkloosheidsBijdrage160(gegevens, zoekDatum);
        } else {
            return BigDecimal.ZERO;
        }
    }

    BigDecimal getWerkloosheidsBijdrage160(SleutelGegevens gegevens, LocalDate zoekDatum) {
        DmfapplWnkengetal werknemersKengetalBijdrage = DmfapplWnkengetal.WERKLOOSHEIDSBIJDRAGE_1_60;
        RszConstant constante = rekenRszConstantService.getRszConstantChecked(gegevens, zoekDatum, werknemersKengetalBijdrage, gegevens.getWerkgeversCategorie());
        return (constante != null) ? constante.getWerkgeversPercentage() : BigDecimal.ZERO;
    }

    BigDecimal getWerkloosheidsBijdrage169(SleutelGegevens gegevens, LocalDate zoekDatum) {
        KengetalMapper werknemersKengetalMapper = getWerknemersKengetalMapper(zoekDatum);
        DmfapplWnkengetal werknemersKengetalBijdrage = werknemersKengetalMapper.getWerkloosheidsbijdrage169();
        RszConstant constante = rekenRszConstantService.getRszConstantChecked(gegevens, zoekDatum, werknemersKengetalBijdrage, gegevens.getWerkgeversCategorie());
        return (constante != null) ? constante.getWerkgeversPercentage() : BigDecimal.ZERO;
    }

    boolean heeftWerkloosheidsBijdrage169(SleutelGegevens gegevens, LocalDate zoekDatum) {
        WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        KengetalMapper werknemersKengetalMapper = getWerknemersKengetalMapper(zoekDatum);
        DmfapplWnkengetal werkloosheidsbijdrage169 = werknemersKengetalMapper.getWerkloosheidsbijdrage169();
        List<DmfapplBasisBijdrage> lijst = dmfapplBasisBijdrageService.findByWerkgeversCategorieWerknemersKengetalWerknemersKengetalBijdrage(
                werkgeversCategorie, werknemersKengetal, werkloosheidsbijdrage169, zoekDatum);
        return !lijst.isEmpty();
    }

    boolean heeftWerkloosheidsBijdrage160(SleutelGegevens gegevens, LocalDate zoekDatum) {
        if (isVakantieregelingPrive(gegevens)) {
            WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
            DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
            List<DmfapplBasisBijdrage> lijst = dmfapplBasisBijdrageService.findByWerkgeversCategorieWerknemersKengetalWerknemersKengetalBijdrage(
                    werkgeversCategorie, werknemersKengetal, DmfapplWnkengetal.WERKLOOSHEIDSBIJDRAGE_1_60, zoekDatum);
            return !lijst.isEmpty();
        } else {
            return false;
        }
    }

