    private Optional<DmfapplWnkengetal> getDmfapplWnkengetalGsd() {
        DmfapplWnkengetal werknemersKengetalBijdrage = null;
        Gsd typeGsd = Gsd.getByCode(constantManager.getByCodeDatum(Konstanten.KST_GSD_DMFAPPL, rekenTijd.eindDatum).getInteger());
        if (typeGsd == Gsd.GSD) {
            werknemersKengetalBijdrage = DmfapplWnkengetal.BIJDRAGE_GSD;
        } else {
            if (typeGsd == Gsd.V_PLUS || typeGsd == Gsd.V_MIN) {
                werknemersKengetalBijdrage = DmfapplWnkengetal.BIJDRAGE_GSD_VLAANDEREN;
            }
        }
        return Optional.ofNullable(werknemersKengetalBijdrage);
    }


    @Override
    public BigDecimal bepaal(ContextKey bijdrageKey, SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal percentageBijdrage = BigDecimal.ZERO;

        if (bijdrageKey == RekenRszKey.BIJDRAGE_RSZ_KEY) {
            percentageBijdrage = getInhoudingRsz(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY) {
            if (zoekDatum.compareTo(RszTools.START_HAFITA) < 0) {
                percentageBijdrage = getPatronaleBijdrageRsz(gegevens, zoekDatum);
            }
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BASISBIJDRAGE_RSZ_ZIV_KEY) {
            if (zoekDatum.compareTo(RszTools.START_HAFITA) >= 0) {
                percentageBijdrage = getPatronaleBijdrageRsz(gegevens, zoekDatum);
            }
        } else if (bijdrageKey == RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_RSZ_KEY) {
            percentageBijdrage = getVerminderingPatronaleBijdrageRsz(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY) {
            boolean isPool2terCheck = isPool2ter.check(getCategorieKengetalStatuutPensioenstelsel(gegevens), zoekDatum);
            percentageBijdrage = isPool2terCheck ?
                    getInhoudingPensioenVastbenoemdenApk(gegevens, zoekDatum) :
                    getInhoudingBijdragePensioen(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY) {
            boolean isPool2terCheck = isPool2ter.check(getCategorieKengetalStatuutPensioenstelsel(gegevens), zoekDatum);
            percentageBijdrage = isPool2terCheck ?
                    getPatronaleBijdragePensioenVastbenoemdenApk(gegevens, zoekDatum) :
                    getPatronaleBijdragePensioen(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY) {
            boolean isPool2terCheck = isPool2ter.check(getCategorieKengetalStatuutPensioenstelsel(gegevens), zoekDatum);
            percentageBijdrage = isPool2terCheck ? BigDecimal.ZERO : getInhoudingPensioenVastbenoemdenApk(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY) {
            boolean isPool2terCheck = isPool2ter.check(getCategorieKengetalStatuutPensioenstelsel(gegevens), zoekDatum);
            percentageBijdrage = isPool2terCheck ? BigDecimal.ZERO : getPatronaleBijdragePensioenVastbenoemdenApk(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_TAO_KEY) {
            percentageBijdrage = getInhoudingTijdelijkeArbeidsOngeschiktheid(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_KEY) {
            percentageBijdrage = getInhoudingDubbelVakantiegeld(gegevens, zoekDatum);
        } else if (PATRONALE_VOERTUIG_KEYS.contains(bijdrageKey)) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_PCT_SOLBIJDRAGE_VOERTUIG, rekenTijd, zoekDatum).getProcentFactor();
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TERUGBETALING_VERKEERSBOETES_KEY) {
            percentageBijdrage = getPatronaleTerugbetalingVerkeersboetes(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY) {
            percentageBijdrage = getInhoudingsPercentageDubbelVakantiegeldMandataris(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY) {
            percentageBijdrage = getPatronaleBijdrageErkentelijkheidsPremie(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_MEER_DAN_10WERKNEMERS_KEY) {
            percentageBijdrage = getPatronaleBijdrageMeerDan10Werknemers(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_PENSIOEN_MANDATARIS_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_PCT_PENS_INH_NBMAND, rekenTijd, zoekDatum).getProcentFactor();
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_MANDATARIS_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_PCT_PENS_BIJDR_NBMAND, rekenTijd, zoekDatum).getProcentFactor();
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY) {
            percentageBijdrage = getPatronaleBijdrageTweedePensioenPijler(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.BIJZONDERE_PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY
                || bijdrageKey == RekenPatronaalRszKey.BIJZONDERE_PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_BIJZONDERE_BIJDRAGE_PENS2, rekenTijd, zoekDatum).getProcentFactor();
        } else if (bijdrageKey == RekenPatronaalRszKey.BEHEERSKOSTEN_PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY
                || bijdrageKey == RekenPatronaalRszKey.BEHEERSKOSTEN_PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_BEHEERSKOSTEN_PENS2, rekenTijd, zoekDatum).getProcentFactor();
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY) {
            percentageBijdrage = bepaalPatronaleBijdrageBonusTweedePensioenPijler(gegevens, zoekDatum, percentageBijdrage);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_WVL_KEY) {
            percentageBijdrage = bijdrageWvl.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_WVL_KEY) {
            percentageBijdrage = patronaleBijdrageWvl.getPercentage(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_GSD_KEY) {
            percentageBijdrage = getPatronaleBijdrageGsd(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_BRUG_PENSIOEN_KEY) {
            percentageBijdrage = constantManager.getByCodeDatum(Konstanten.KST_PCT_BIJDRAGE_BRUG_PENSIOEN, rekenTijd.eindDatum).getProcentFactor();
        } else if (bijdrageKey == RekenRszKey.BIJDRAGE_MOBILITEITSBUDGET_KEY) {
            percentageBijdrage = getInhoudingMobiliteitsBudget(gegevens, zoekDatum);
        } else if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJDRAGE_CORONAPREMIE_KEY) {
            return patronaleBijdrageCoronaPremie.getPercentage(gegevens, zoekDatum);
        } else {
            log.warn("Voor {} is geen percentage gedefinieerd", bijdrageKey);
        }

        log.trace("percentageBijdrage {}:{}", bijdrageKey, percentageBijdrage);

        return percentageBijdrage;
    }

    protected abstract CategorieKengetalStatuutPensioenstelsel getCategorieKengetalStatuutPensioenstelsel(SleutelGegevens gegevens);

    private BigDecimal bepaalPatronaleBijdrageBonusTweedePensioenPijler(SleutelGegevens gegevens, LocalDate zoekDatum, BigDecimal percentageBijdrage) {
        VrijstelPens2 vrijstelling = gegevens.getVrijstellingTweedePensioenpijler();
        if (vrijstelling == VrijstelPens2.BONUSBIJDRAGE || vrijstelling == VrijstelPens2.WN_PROVANT_BONUS_A) {
            return constantManager.getActualConstant(Konstanten.KST_BIJDRAGE_PENS2B, rekenTijd, zoekDatum).getProcentFactor();
        } else if (vrijstelling == VrijstelPens2.BONUSBIJDRAGE2 || vrijstelling == VrijstelPens2.WN_PROVANT_BONUS_B) {
            return constantManager.getActualConstant(Konstanten.KST_BIJDRAGE_PENS2B_PERC2, rekenTijd, zoekDatum).getProcentFactor();
        } else {
            return percentageBijdrage;
        }
    }

    protected KengetalMapper getWerknemersKengetalMapper(LocalDate zoekDatum) {
        return KengetalMapperFactory.getKengetalMapper(zoekDatum);
    }
